<template>
  <view class="page-shell"><view class="page-content"><view class="summary-card"><view><text class="summary-title">接单设置</text><text class="summary-desc">排班、请假和服务区域会影响商户派单</text></view><u-switch v-model="form.enabled" active-color="#00B8A9" /></view><view class="settings-card"><view class="setting-row"><view><text class="setting-title">每日接单上限</text><text class="setting-desc">达到上限后商户不可继续派单</text></view><view class="stepper"><text @click="adjustLimit(-1)">−</text><text>{{ form.maxDailyOrders }}</text><text @click="adjustLimit(1)">+</text></view></view><text class="section-title area-title">服务区域</text><view class="area-tags"><text v-for="area in areaOptions" :key="area" :class="{ active: form.serviceAreas.includes(area) }" @click="toggleArea(area)">{{ area }}</text></view></view><view class="section-head"><view><text class="section-title">未来 7 天排班</text><text class="section-desc">点击时段切换可接单状态，整日请假会清空时段</text></view></view><view class="schedule-card"><view v-for="day in form.days" :key="day.date" class="day-row" :class="{ leave: day.onLeave }"><view class="day-head"><view><text class="day-name">{{ dayName(day.date) }}</text><text class="day-date">{{ day.date.slice(5) }}</text></view><view class="leave-toggle" :class="{ active: day.onLeave }" @click="toggleLeave(day)">{{ day.onLeave ? '取消请假' : '整日请假' }}</view></view><input v-if="day.onLeave" v-model="day.leaveReason" class="leave-reason" placeholder="请假原因（选填）" /><view v-else class="slots"><text v-for="slot in SCHEDULE_SLOTS" :key="slot.value" :class="{ active: day.slots.includes(slot.value) }" @click="toggleSlot(day, slot.value)">{{ slot.label }}<small>{{ slot.time }}</small></text></view></view></view><view class="tip-card"><u-icon name="info-circle" size="20" color="#3A7BF7" /><text>当前使用区级服务范围进行前端冲突判断，真实距离与路程时间需后端地图服务支持。</text></view><button class="save-button" :disabled="saving" @click="save">{{ saving ? '保存中...' : '保存排班设置' }}</button></view><role-tab-bar :tabs="tabs" current="/subpkg-caregiver/schedule/index" /></view>
</template>
<script setup>
import { computed, reactive, ref } from 'vue'
import { onShow } from '@dcloudio/uni-app'
import RoleTabBar from '@/components/base/role-tab-bar.vue'
import { CAREGIVER_TABS } from '@/constants/caregiver-navigation.js'
import { SCHEDULE_SLOTS } from '@/constants/caregiver-schedule.js'
import { ROLES } from '@/constants/roles.js'
import { useCaregiverStore } from '@/store/caregiver.js'
import { useNotificationStore } from '@/store/notification.js'
import { requireRole } from '@/utils/permission.js'
const caregiverStore = useCaregiverStore(); const notificationStore = useNotificationStore(); const tabs = computed(() => CAREGIVER_TABS.map((tab) => tab.label === '我的' ? { ...tab, badge: notificationStore.unreadCount || '' } : tab)); const saving = ref(false); const areaOptions = ['朝阳区', '海淀区', '东城区', '西城区', '丰台区']; const form = reactive({ enabled: true, maxDailyOrders: 3, serviceAreas: [], days: [] }); onShow(async () => { if (!requireRole(ROLES.CAREGIVER)) return; const [schedule] = await Promise.all([caregiverStore.fetchSchedule(), notificationStore.fetchUnreadCount()]); Object.assign(form, { enabled: schedule.enabled, maxDailyOrders: schedule.maxDailyOrders, serviceAreas: [...schedule.serviceAreas], days: schedule.days.map((day) => ({ ...day, slots: [...day.slots] })) }) }); function adjustLimit(value) { form.maxDailyOrders = Math.max(1, Math.min(10, form.maxDailyOrders + value)) } function toggleArea(area) { const index = form.serviceAreas.indexOf(area); if (index >= 0) form.serviceAreas.splice(index, 1); else form.serviceAreas.push(area) } function toggleSlot(day, slot) { const index = day.slots.indexOf(slot); if (index >= 0) day.slots.splice(index, 1); else day.slots.push(slot) } function toggleLeave(day) { day.onLeave = !day.onLeave; if (day.onLeave) day.slots = []; else day.leaveReason = '' } function dayName(date) { const value = new Date(`${date}T00:00:00`); return ['周日','周一','周二','周三','周四','周五','周六'][value.getDay()] } async function save() { if (!form.serviceAreas.length) return uni.showToast({ title: '请至少选择一个服务区域', icon: 'none' }); saving.value = true; try { await caregiverStore.saveSchedule({ enabled: form.enabled, maxDailyOrders: form.maxDailyOrders, serviceAreas: [...form.serviceAreas], days: form.days.map((day) => ({ ...day, slots: [...day.slots] })) }); uni.showToast({ title: '排班已保存', icon: 'success' }) } finally { saving.value = false } }
</script>
<style lang="scss" scoped>
.page-shell{min-height:100vh;background:$page-gradient}.page-content{padding:24rpx $spacing-base calc(140rpx + env(safe-area-inset-bottom))}.summary-card{display:flex;align-items:center;justify-content:space-between;padding:28rpx 24rpx;border-radius:28rpx;color:#fff;background:$primary-gradient;box-shadow:$shadow-float}.summary-title,.summary-desc,.setting-title,.setting-desc,.section-title,.section-desc,.day-name,.day-date{display:block}.summary-title{font-size:$font-size-md;font-weight:700}.summary-desc{margin-top:7rpx;font-size:$font-size-xs;opacity:.78}.settings-card,.schedule-card{margin-top:20rpx;padding:24rpx;border:$glass-border-soft;border-radius:28rpx;background:$surface-gradient;box-shadow:$shadow-sm}.setting-row{display:flex;align-items:center;justify-content:space-between;gap:20rpx}.setting-title{color:$text-color;font-size:$font-size-sm;font-weight:700}.setting-desc{margin-top:5rpx;color:$text-color-hint;font-size:$font-size-xs}.stepper{display:flex;align-items:center;overflow:hidden;border:1rpx solid $border-color;border-radius:$radius-round}.stepper text{display:flex;align-items:center;justify-content:center;min-width:58rpx;height:58rpx;color:$primary-color;background:#fff;font-size:27rpx}.stepper text:nth-child(2){color:$text-color;background:$primary-bg;font-size:$font-size-sm}.area-title{margin-top:27rpx}.area-tags{display:flex;flex-wrap:wrap;gap:10rpx;margin-top:14rpx}.area-tags text{padding:10rpx 17rpx;border:1rpx solid $border-color;border-radius:$radius-round;color:$text-color-hint;background:#fff;font-size:$font-size-xs}.area-tags text.active{border-color:rgba(58,123,247,.25);color:$primary-color;background:$primary-bg}.section-head{margin:29rpx 4rpx 16rpx}.section-title{color:$text-color;font-size:$font-size-md;font-weight:700}.section-desc{margin-top:5rpx;color:$text-color-hint;font-size:$font-size-xs}.schedule-card{padding-top:4rpx;padding-bottom:4rpx}.day-row{padding:20rpx 0;border-bottom:1rpx solid $divider-color}.day-row:last-child{border-bottom:0}.day-row.leave{opacity:.78}.day-head{display:flex;align-items:center;justify-content:space-between}.day-name{color:$text-color;font-size:$font-size-base;font-weight:600}.day-date{margin-top:4rpx;color:$text-color-hint;font-size:$font-size-xs}.leave-toggle{padding:8rpx 14rpx;border-radius:$radius-round;color:$warning-color;background:#fff2eb;font-size:$font-size-xs}.leave-toggle.active{color:$primary-color;background:$primary-bg}.slots{display:grid;grid-template-columns:repeat(3,1fr);gap:10rpx;margin-top:14rpx}.slots>text{padding:12rpx 4rpx;border:1rpx solid $border-color;border-radius:17rpx;color:$text-color-hint;background:#fff;font-size:$font-size-xs;text-align:center}.slots>text.active{border-color:rgba(0,184,169,.25);color:$success-color;background:#e9fbf7}.slots small{display:block;margin-top:4rpx;font-size:17rpx}.leave-reason{height:68rpx;margin-top:13rpx;padding:0 15rpx;border:1rpx solid rgba(255,138,92,.18);border-radius:17rpx;background:#fff7f2;font-size:$font-size-xs}.tip-card{display:flex;align-items:flex-start;gap:10rpx;margin-top:20rpx;padding:19rpx;border-radius:21rpx;color:$text-color-secondary;background:$primary-bg;font-size:$font-size-xs;line-height:1.55}.save-button{height:82rpx;margin-top:20rpx;border:0;border-radius:$radius-round;color:#fff;background:$primary-gradient;line-height:82rpx}.save-button::after{border:0}
</style>
